/**
 * Single composition point for wrapping a Zod type factory with all
 * security-related enhancements. Currently emits a secure metric.
 *
 * If new features are added in the future, apply them here once
 * and all wrapped types benefit automatically.
 */
export declare const createSecureType: <F extends (...args: Array<any>) => any>(fn: F) => F;
/**
 * Same as `createSecureType` but for a coerce-style object (z.coerce).
 * Wraps each factory method except `string`, which is not inherently
 * secure and requires explicit validation (e.g. .secure()).
 */
export declare const createSecureCoerce: <T extends Record<string, (...args: Array<any>) => any>>(coerceObj: T) => T;
